INSERT INTO checklists (user_id, payload) VALUES
(null, '{"name":"SOP Episodio Semanal","area":"Producción","frequency":"Semanal","status":"Pendiente","items":[{"id":"sop1","item":"Definir herida emocional central del episodio","completed":false,"critical":true},{"id":"sop2","item":"Definir símbolo narrativo del episodio","completed":false,"critical":true},{"id":"sop3","item":"Escribir guion completo (estructura AZTIYARTE 9 bloques)","completed":false,"critical":true},{"id":"sop4","item":"Revisar que no haya consejos directos en el guion","completed":false,"critical":true},{"id":"sop5","item":"Grabar audio con ElevenLabs o voz real","completed":false,"critical":true},{"id":"sop6","item":"Editar audio (limpiar silencios, normalizar volumen)","completed":false,"critical":false},{"id":"sop7","item":"Generar 12 assets visuales (pipeline SB-01)","completed":false,"critical":false},{"id":"sop8","item":"Escribir descripción Spotify (150-200 palabras)","completed":false,"critical":false},{"id":"sop9","item":"Completar episodio en AMTMEapp con todos los campos","completed":false,"critical":false},{"id":"sop10","item":"Programar publicación en Spotify","completed":false,"critical":true}],"readyCriteria":"Guion completo + audio editado + descripción Spotify + al menos 6 assets visuales listos.","errorsToAvoid":"Publicar sin descripción completa. Guion con consejos directos. Assets fuera de paleta SB-01."}'),
(null, '{"name":"QA Visual Pre-Publicación","area":"Visual","frequency":"Por episodio","status":"Pendiente","items":[{"id":"qa1","item":"Paleta: Navy #0C1F36, Lemon Lime #FEE94B, Crema #F5F2EA","completed":false,"critical":true},{"id":"qa2","item":"Tipografía: Josefin Sans Bold en titulares","completed":false,"critical":true},{"id":"qa3","item":"Sin cursivas en ninguna pieza","completed":false,"critical":true},{"id":"qa4","item":"Sin Barra de Navidad ni micro-firma antigua","completed":false,"critical":true},{"id":"qa5","item":"Contraste legible texto sobre fondo (mínimo 4.5:1)","completed":false,"critical":false},{"id":"qa6","item":"Formato correcto por plataforma (1:1, 4:5, 9:16)","completed":false,"critical":false},{"id":"qa7","item":"Sin paleta Cobalt antigua (#1A1AE6)","completed":false,"critical":true},{"id":"qa8","item":"Cover Spotify: texto legible a 100x100px","completed":false,"critical":false},{"id":"qa9","item":"Al menos 12 piezas generadas del pipeline","completed":false,"critical":false}],"readyCriteria":"Todas las piezas en paleta SB-01. Sin cursivas. Formatos correctos por plataforma.","errorsToAvoid":"Mezclar paletas antiguas y nueva. Publicar assets con cursivas. Ignorar proporción de aspect ratio."}'),
(null, '{"name":"Ritual Dominical","area":"Energía","frequency":"Semanal (domingo)","status":"Pendiente","items":[{"id":"rd1","item":"Revisar métricas de la semana anterior","completed":false,"critical":true},{"id":"rd2","item":"Registrar streams y datos en tabla Métricas AMTMEapp","completed":false,"critical":true},{"id":"rd3","item":"Definir tema del episodio de la semana entrante","completed":false,"critical":true},{"id":"rd4","item":"Revisar leads de monetización pendientes","completed":false,"critical":false},{"id":"rd5","item":"Revisar checklists incompletos de la semana","completed":false,"critical":false},{"id":"rd6","item":"Actualizar calendario editorial","completed":false,"critical":false},{"id":"rd7","item":"Evaluar energía personal y ajustar carga si es necesario","completed":false,"critical":true},{"id":"rd8","item":"Registrar un aprendizaje de la semana en Notas","completed":false,"critical":false}],"readyCriteria":"Métricas registradas + tema siguiente definido + energía evaluada.","errorsToAvoid":"Saltarse el ritual más de 2 semanas seguidas. Confundir revisión con planificación (son bloques separados)."}'),
(null, '{"name":"Checklist Deploy AMTMEapp","area":"Técnica","frequency":"Por release","status":"Pendiente","items":[{"id":"dep1","item":"Ejecutar npx next build sin errores","completed":false,"critical":true},{"id":"dep2","item":"Verificar que landing pública / funciona sin auth","completed":false,"critical":true},{"id":"dep3","item":"Verificar login /auth/sign-in funciona","completed":false,"critical":true},{"id":"dep4","item":"Confirmar variables de entorno en Vercel","completed":false,"critical":true},{"id":"dep5","item":"Verificar que datos cargan desde Supabase en /episodios","completed":false,"critical":true},{"id":"dep6","item":"Confirmar que StudioShell no aparece en landing pública","completed":false,"critical":true},{"id":"dep7","item":"Hacer git commit --no-verify con mensaje descriptivo","completed":false,"critical":false},{"id":"dep8","item":"Verificar build exitoso en Vercel dashboard","completed":false,"critical":true}],"readyCriteria":"Build sin errores + landing pública funcional + studio con datos reales + Vercel deployment verde.","errorsToAvoid":"Hacer push sin build local. Olvidar variables de entorno en Vercel. Commit con npm run build (usar npx next build)."}'),
(null, '{"name":"Venta Tarot Ética","area":"Monetización","frequency":"Por lectura","status":"Pendiente","items":[{"id":"vt1","item":"Confirmar que el cliente entiende que es autoconocimiento, no predicción","completed":false,"critical":true},{"id":"vt2","item":"Aclarar precio y duración antes de comenzar (30-45 min)","completed":false,"critical":true},{"id":"vt3","item":"Confirmar pago antes de la sesión","completed":false,"critical":true},{"id":"vt4","item":"Registrar lead en AMTMEapp /monetización","completed":false,"critical":false},{"id":"vt5","item":"No ofrecer diagnóstico psicológico ni médico","completed":false,"critical":true},{"id":"vt6","item":"No hacer promesas sobre el futuro","completed":false,"critical":true},{"id":"vt7","item":"Cerrar sesión con una pregunta abierta, no con una respuesta cerrada","completed":false,"critical":false},{"id":"vt8","item":"Actualizar status del lead en AMTMEapp post-sesión","completed":false,"critical":false}],"readyCriteria":"Pago confirmado + encuadre ético establecido + sesión completada + lead actualizado.","errorsToAvoid":"Hacer lectura sin pago. Prometer certeza sobre el futuro. Confundir rol de lector con rol de terapeuta."}'),
(null, '{"name":"Cierre Mensual AMTME OS","area":"Métricas","frequency":"Mensual (día 1-5)","status":"Pendiente","items":[{"id":"cm1","item":"Registrar métricas completas del mes en tabla Métricas","completed":false,"critical":true},{"id":"cm2","item":"Calcular conversión episodio → DM → venta","completed":false,"critical":true},{"id":"cm3","item":"Identificar episodio de mayor y menor retención","completed":false,"critical":false},{"id":"cm4","item":"Registrar ingresos totales del mes","completed":false,"critical":true},{"id":"cm5","item":"Revisar checklists de calidad del mes","completed":false,"critical":false},{"id":"cm6","item":"Actualizar roadmap con aprendizajes del mes","completed":false,"critical":false},{"id":"cm7","item":"Definir 3 prioridades para el mes siguiente","completed":false,"critical":true},{"id":"cm8","item":"Revisar si hay leads calientes sin cerrar","completed":false,"critical":false}],"readyCriteria":"Métricas registradas + ingresos documentados + 3 prioridades mes siguiente definidas.","errorsToAvoid":"Cerrar el mes sin registrar ingresos. Saltarse el análisis de conversión. Definir más de 3 prioridades (pierde enfoque)."}'),
(null, '{"name":"Portada Spotify","area":"Visual","frequency":"Por temporada o rebrand","status":"Pendiente","items":[{"id":"ps1","item":"Dimensiones: 3000x3000px mínimo, formato cuadrado","completed":false,"critical":true},{"id":"ps2","item":"Nombre del podcast legible a 100x100px","completed":false,"critical":true},{"id":"ps3","item":"Paleta SB-01 activa (Navy + Lemon Lime o Crema)","completed":false,"critical":true},{"id":"ps4","item":"Sin texto secundario pequeño (ilegible en mobile)","completed":false,"critical":false},{"id":"ps5","item":"JPG o PNG, máximo 500KB","completed":false,"critical":true},{"id":"ps6","item":"Revisar en móvil antes de subir (vista previa)","completed":false,"critical":false},{"id":"ps7","item":"Subir en Spotify for Podcasters","completed":false,"critical":true}],"readyCriteria":"3000x3000px + nombre legible en miniatura + paleta correcta + formato correcto.","errorsToAvoid":"Usar paleta antigua. Subir con texto ilegible en miniatura. Olvidar revisar en móvil."}'),
(null, '{"name":"Revisión Pre-Publicación Episodio","area":"Editorial","frequency":"Por episodio","status":"Pendiente","items":[{"id":"rp1","item":"Herida emocional identificable en primeros 90 segundos","completed":false,"critical":true},{"id":"rp2","item":"Sin consejos directos tipo debes hacer X","completed":false,"critical":true},{"id":"rp3","item":"Estructura AZTIYARTE completa (9 bloques)","completed":false,"critical":true},{"id":"rp4","item":"CTA único, claro, no imperativo","completed":false,"critical":true},{"id":"rp5","item":"Descripción Spotify 150-200 palabras","completed":false,"critical":false},{"id":"rp6","item":"Sin palabras: sanar, crecer, evolucionar, vibrar, manifestar","completed":false,"critical":true},{"id":"rp7","item":"Tono: no condescendiente, no didáctico","completed":false,"critical":true},{"id":"rp8","item":"Duración: entre 10 y 15 minutos","completed":false,"critical":false}],"readyCriteria":"Los 5 criterios críticos en verde. Descripción lista. Audio final exportado.","errorsToAvoid":"Publicar con consejos directos. Ignorar filtro de palabras prohibidas. Episodio sin CTA."}'),
(null, '{"name":"Distribución IG/TikTok","area":"Distribución","frequency":"Por episodio","status":"Pendiente","items":[{"id":"di1","item":"Clip principal de 60-90s editado con subtítulos","completed":false,"critical":true},{"id":"di2","item":"Caption con hook en primera línea (sin truncar)","completed":false,"critical":true},{"id":"di3","item":"3 hashtags relevantes (no más)","completed":false,"critical":false},{"id":"di4","item":"CTA hacia Spotify en bio o caption","completed":false,"critical":true},{"id":"di5","item":"Story con link al episodio","completed":false,"critical":false},{"id":"di6","item":"Carrusel de concepto clave del episodio","completed":false,"critical":false},{"id":"di7","item":"Programar en horario óptimo: 7-9pm México","completed":false,"critical":false},{"id":"di8","item":"Registrar publicación en calendario AMTMEapp","completed":false,"critical":false}],"readyCriteria":"Reel publicado + caption con hook + link a Spotify activo.","errorsToAvoid":"Caption que comienza con el título del episodio (truncado en feed). Publicar sin caption. Reel sin subtítulos."}'),
(null, '{"name":"Clipping de Episodio","area":"Producción","frequency":"Por episodio","status":"Pendiente","items":[{"id":"cl1","item":"Identificar 3-5 momentos de mayor impacto emocional","completed":false,"critical":true},{"id":"cl2","item":"Cortar clips de 30-90 segundos cada uno","completed":false,"critical":true},{"id":"cl3","item":"Agregar subtítulos (auto + revisión manual)","completed":false,"critical":true},{"id":"cl4","item":"Formato 9:16 para Reels/TikTok","completed":false,"critical":true},{"id":"cl5","item":"Formato 1:1 para posts de feed","completed":false,"critical":false},{"id":"cl6","item":"Agregar identidad visual: logo o colores SB-01","completed":false,"critical":false},{"id":"cl7","item":"Guardar clips en Drive carpeta del episodio","completed":false,"critical":false}],"readyCriteria":"Mínimo 1 clip 9:16 con subtítulos listo para publicar.","errorsToAvoid":"Clips de más de 90s (pierden retención). Sin subtítulos. Olvidar guardar en Drive."}'),
(null, '{"name":"Revisión de Métricas Mensual","area":"Métricas","frequency":"Mensual","status":"Pendiente","items":[{"id":"rm1","item":"Descargar reporte Spotify for Creators","completed":false,"critical":true},{"id":"rm2","item":"Identificar episodio con mayor retención del mes","completed":false,"critical":true},{"id":"rm3","item":"Calcular tasa episodio→DM del mes","completed":false,"critical":true},{"id":"rm4","item":"Comparar con mes anterior","completed":false,"critical":false},{"id":"rm5","item":"Registrar en tabla Métricas de AMTMEapp","completed":false,"critical":true},{"id":"rm6","item":"Generar reporte automático con IA (tab Reportes en /métricas)","completed":false,"critical":false},{"id":"rm7","item":"Definir hipótesis para episodio del mes siguiente","completed":false,"critical":false}],"readyCriteria":"Datos registrados en AMTMEapp + 1 insight accionable identificado.","errorsToAvoid":"Revisar métricas sin registrarlas. Obsesionarse con números absolutos vs. tendencias."}'),
(null, '{"name":"Seguimiento Comercial","area":"Monetización","frequency":"Semanal","status":"Pendiente","items":[{"id":"sc1","item":"Revisar leads activos en /monetización AMTMEapp","completed":false,"critical":true},{"id":"sc2","item":"Identificar leads sin respuesta hace más de 48h","completed":false,"critical":true},{"id":"sc3","item":"Generar follow-up con IA para leads calientes","completed":false,"critical":false},{"id":"sc4","item":"Actualizar status de cada lead","completed":false,"critical":true},{"id":"sc5","item":"Registrar ingresos de la semana","completed":false,"critical":false},{"id":"sc6","item":"Identificar patrón en leads que convirtieron vs. los que no","completed":false,"critical":false}],"readyCriteria":"Todos los leads con status actualizado + follow-ups enviados a leads calientes.","errorsToAvoid":"Dejar leads sin respuesta más de 48h. No registrar ingresos en la semana."}'),
(null, '{"name":"Calendario Editorial","area":"Producción","frequency":"Quincenal","status":"Pendiente","items":[{"id":"ce1","item":"Planificar episodios de las próximas 2 semanas","completed":false,"critical":true},{"id":"ce2","item":"Definir tema, herida y símbolo de cada episodio","completed":false,"critical":true},{"id":"ce3","item":"Asignar fechas de grabación y publicación","completed":false,"critical":true},{"id":"ce4","item":"Registrar en calendario AMTMEapp","completed":false,"critical":false},{"id":"ce5","item":"Verificar que no hay dos episodios del mismo pilar consecutivos","completed":false,"critical":false},{"id":"ce6","item":"Planificar contenido IG de apoyo por episodio","completed":false,"critical":false}],"readyCriteria":"2 semanas de producción definidas con tema + herida + símbolo + fecha.","errorsToAvoid":"Planificar más de 4 semanas (pierde flexibilidad). No confirmar fecha de grabación."}'),
(null, '{"name":"Grabación de Episodio","area":"Producción","frequency":"Por episodio","status":"Pendiente","items":[{"id":"gr1","item":"Guion final impreso o en pantalla visible","completed":false,"critical":true},{"id":"gr2","item":"Ambiente silencioso verificado","completed":false,"critical":true},{"id":"gr3","item":"Nivel de grabación verificado (-12 a -6 dB)","completed":false,"critical":false},{"id":"gr4","item":"Primera toma completa sin pausas (para ritmo natural)","completed":false,"critical":false},{"id":"gr5","item":"Grabar intros y outros por separado si es necesario","completed":false,"critical":false},{"id":"gr6","item":"Guardar archivo raw en Drive inmediatamente","completed":false,"critical":true}],"readyCriteria":"Audio raw guardado en Drive. Nivel de grabación correcto. Sin ruido de fondo evidente.","errorsToAvoid":"Grabar sin guion final. Olvidar guardar raw antes de editar. Nivel de grabación saturado."}'),
(null, '{"name":"Edición de Episodio","area":"Producción","frequency":"Por episodio","status":"Pendiente","items":[{"id":"ed1","item":"Limpiar silencios largos (más de 2 segundos)","completed":false,"critical":false},{"id":"ed2","item":"Normalizar volumen final (-16 LUFS para podcast)","completed":false,"critical":true},{"id":"ed3","item":"Agregar intro y outro si aplica","completed":false,"critical":false},{"id":"ed4","item":"Exportar en MP3 192kbps mínimo","completed":false,"critical":true},{"id":"ed5","item":"Revisar corte completo una vez antes de exportar","completed":false,"critical":true},{"id":"ed6","item":"Guardar exportación final en Drive carpeta del episodio","completed":false,"critical":true}],"readyCriteria":"MP3 exportado a -16 LUFS + guardado en Drive + escucha de revisión completa.","errorsToAvoid":"Exportar sin normalizar. No hacer escucha de revisión. Olvidar guardar en Drive."}'),
(null, '{"name":"Respaldo en Drive","area":"Técnica","frequency":"Semanal","status":"Pendiente","items":[{"id":"rb1","item":"Audio raw de episodio en carpeta Drive del episodio","completed":false,"critical":true},{"id":"rb2","item":"Audio editado final en carpeta Drive del episodio","completed":false,"critical":true},{"id":"rb3","item":"Assets visuales del episodio en carpeta Drive","completed":false,"critical":false},{"id":"rb4","item":"Guion final en Drive (texto o doc)","completed":false,"critical":true},{"id":"rb5","item":"Verificar acceso desde otro dispositivo","completed":false,"critical":false}],"readyCriteria":"Audio raw + audio final + guion guardados en Drive. Acceso verificado.","errorsToAvoid":"Solo tener archivos en local sin respaldo. No organizar por carpeta de episodio."}');
